import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"高度な機能: 詳細設定 | opencode-mystatus","description":"opencode-mystatusの高度な設定オプションを学びます。Google Cloud複数アカウント管理、Copilot認証設定、多言語サポートなどのカスタマイズ機能を紹介します。","frontmatter":{"title":"高度な機能: 詳細設定 | opencode-mystatus","sidebarTitle":"高度な機能","subtitle":"高度な機能: 詳細設定","description":"opencode-mystatusの高度な設定オプションを学びます。Google Cloud複数アカウント管理、Copilot認証設定、多言語サポートなどのカスタマイズ機能を紹介します。","order":3},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/advanced/index.md","filePath":"ja/vbgate/opencode-mystatus/advanced/index.md"}'),i={name:"ja/vbgate/opencode-mystatus/advanced/index.md"};function d(r,a,n,h,s,u){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><p>この章では、opencode-mystatusの高度な設定オプションを紹介します。より多くのカスタマイズが必要なユーザーに適しています。</p><h2 id="機能リスト" tabindex="-1">機能リスト <a class="header-anchor" href="#機能リスト" aria-label="Permalink to &quot;機能リスト&quot;">​</a></h2><h3 id="google-cloud設定" tabindex="-1"><a href="./google-setup/">Google Cloud設定</a> <a class="header-anchor" href="#google-cloud設定" aria-label="Permalink to &quot;[Google Cloud設定](./google-setup/)&quot;">​</a></h3><p>複数のGoogle Cloud Antigravityアカウントを設定・管理します：</p><ul><li>複数のGoogle Cloudアカウントを追加</li><li>4つのモデル（G3 Pro、G3 Image、G3 Flash、Claude）のマッピング関係</li><li>projectIdとmanagedProjectIdの違い</li><li>単一アカウントモデルクォータ不足の問題を解決</li></ul><h3 id="copilot認証設定" tabindex="-1"><a href="./copilot-auth/">Copilot認証設定</a> <a class="header-anchor" href="#copilot認証設定" aria-label="Permalink to &quot;[Copilot認証設定](./copilot-auth/)&quot;">​</a></h3><p>GitHub Copilot認証の問題を解決します：</p><ul><li>OAuth TokenとFine-grained PATの違い</li><li>OAuth Token権限不足の問題を解決</li><li>Fine-grained PATを作成してサブスクリプションタイプを設定</li><li><code>copilot-quota-token.json</code> ファイルを設定</li></ul><h3 id="多言語サポート" tabindex="-1"><a href="./i18n-setup/">多言語サポート</a> <a class="header-anchor" href="#多言語サポート" aria-label="Permalink to &quot;[多言語サポート](./i18n-setup/)&quot;">​</a></h3><p>自動言語検出メカニズムを理解します：</p><ul><li>システム言語の自動検出原理</li><li>Intl APIと環境変数のフォールバックメカニズム</li><li>出力言語の切り替え方法（日本語/英語）</li></ul><h2 id="適用シナリオ" tabindex="-1">適用シナリオ <a class="header-anchor" href="#適用シナリオ" aria-label="Permalink to &quot;適用シナリオ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>推奨チュートリアル</th></tr></thead><tbody><tr><td>複数のGoogleアカウントを使用</td><td><a href="./google-setup/">Google Cloud設定</a></td></tr><tr><td>Copilotクォータクエリが失敗</td><td><a href="./copilot-auth/">Copilot認証設定</a></td></tr><tr><td>出力言語を切り替えたい</td><td><a href="./i18n-setup/">多言語サポート</a></td></tr></tbody></table><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>この章を学習する前に、以下を完了することをお勧めします：</p><ul><li><a href="./../start/">クイックスタート</a> - プラグインインストールの完了</li><li><a href="./../platforms/">プラットフォーム機能</a> - 各プラットフォームの基本用法の理解</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>問題に遭遇しましたか？<a href="./../faq/">よくある質問</a> でヘルプを確認してください。</p>',19)])])}const m=e(i,[["render",d]]);export{p as __pageData,m as default};
